if (!function_exists('sd_t')) {
  function sd_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('sd_h')) {
  function sd_h($key, $fallback = '') { return htmlspecialchars((string) sd_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('sd_js')) {
  function sd_js($key, $fallback = '') { return json_encode(sd_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
$defaultFrom=date('Y-m-01');$defaultTo=date('Y-m-d');
$customers=$db->query("SELECT kode_penerima,nama FROM penerima ORDER BY nama");
$currencies=$db->query("SELECT DISTINCT valuta FROM sales_invoice WHERE valuta IS NOT NULL AND valuta<>'' ORDER BY valuta");
$kpi=$db->fetch("SELECT COUNT(*) invoice_count,COALESCE(SUM(d.subtotal),0) subtotal,COALESCE(SUM(CASE WHEN si.tax='1' THEN d.subtotal*0.11 ELSE 0 END),0) tax_amount,COALESCE(SUM(d.subtotal + CASE WHEN si.tax='1' THEN d.subtotal*0.11 ELSE 0 END),0) grand_total FROM sales_invoice si LEFT JOIN (SELECT id_sales,SUM(nilai) subtotal FROM sales_invoice_detail GROUP BY id_sales) d ON d.id_sales=si.id_sales WHERE si.invoice_date BETWEEN ? AND ?",array($defaultFrom,$defaultTo));
?>
