<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script>
<script>
function bhError(m){$('.isi_warning_delete').text(m||<?=sd_js('sales_billing_history_process_failed', 'Billing History failed to process.');?>);$('.error_data_delete').fadeIn();}
function bhFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),customer:$('#filter_customer').val(),currency:$('#filter_currency').val(),tax_status:$('#filter_tax_status').val(),keyword:$('#filter_keyword').val()};}
function bhQuery(){return $.param(bhFilters());}
$(function(){if($.fn.datepicker){$('.bh-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_customer,#filter_currency,#filter_tax_status').select2({width:'100%',allowClear:true});}
var dt=$('#dtb_billing_history').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=sd_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'38px',targets:0},{width:'78px',targets:1}],ajax:{url:'<?=base_admin();?>modul/billing_history/billing_history_data.php',type:'post',data:function(d){$.extend(d,bhFilters());},error:function(xhr){console.log(xhr.responseText);bhError(<?=sd_js('sales_billing_history_load_failed', 'Billing History data failed to load.');?>);}}});
$('#btn_filter_bh').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_bh').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_customer,#filter_currency,#filter_tax_status').val('').trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_excel_bh').click(function(){window.location='<?=base_admin();?>modul/billing_history/billing_history_action.php?act=excel&'+bhQuery();});
$(document).on('click','.btn-bh-detail',function(){$.post('<?=base_admin();?>modul/billing_history/billing_history_action.php?act=detail',{id:$(this).data('id')},function(html){$('#bh_detail_body').html(html);$('#modal_detail_bh').modal('show');}).fail(function(){bhError('Detail gagal dibuka.');});});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
});
</script>
